// Bundles the eval browser harness page runtime (server/utils/browser-harness/
// host-page.ts) into a self-contained browser IIFE, emitted as a generated TS
// const that the Node harness injects into the Playwright page. Mirrors the
// `bundle:sandbox-proxies` pattern (generated .ts consumed at runtime, wired
// into `pretest` + `build`). Auto-generated output is gitignored.
import { build } from "esbuild";
import { fileURLToPath } from "url";
import { dirname, join, resolve } from "path";
import { writeFileSync } from "fs";

const __filename = fileURLToPath(import.meta.url);
const __dirname = dirname(__filename);
const inspectorRoot = join(__dirname, "..");
const clientSrc = resolve(inspectorRoot, "client/src");
const sharedDir = resolve(inspectorRoot, "shared");

const entry = resolve(
  inspectorRoot,
  "server/utils/browser-harness/host-page.ts",
);
const outputTsPath = resolve(
  inspectorRoot,
  "server/utils/browser-harness/HarnessPageBundle.generated.ts",
);

// Resolve the client-side `@/` and `@/shared` path aliases the way the client
// tsconfig/vite does, so host-app-bridge.ts (and its transitive imports)
// resolve from the server-located entry.
const aliasPlugin = {
  name: "mcpjam-client-alias",
  setup(b) {
    b.onResolve({ filter: /^@\// }, async (args) => {
      const rewritten = args.path.startsWith("@/shared/")
        ? resolve(sharedDir, args.path.slice("@/shared/".length))
        : resolve(clientSrc, args.path.slice("@/".length));
      // Delegate to esbuild's resolver so extension + index resolution runs.
      const r = await b.resolve(rewritten, {
        kind: args.kind,
        resolveDir: dirname(rewritten),
      });
      if (r.errors.length) return { errors: r.errors };
      return { path: r.path, external: r.external };
    });
  },
};

try {
  const result = await build({
    entryPoints: [entry],
    bundle: true,
    format: "iife",
    platform: "browser",
    target: "es2022",
    write: false,
    legalComments: "none",
    plugins: [aliasPlugin],
    // Resolve .ts/.tsx without explicit extensions, matching the client.
    resolveExtensions: [".ts", ".tsx", ".mjs", ".js", ".json"],
    logLevel: "warning",
  });

  const js = result.outputFiles[0].text;
  const outputContent = `// This file is auto-generated by scripts/bundle-browser-harness.mjs
// Do not edit directly — modify server/utils/browser-harness/host-page.ts.
/* eslint-disable */

export const HARNESS_PAGE_BUNDLE = ${JSON.stringify(js)};
`;
  writeFileSync(outputTsPath, outputContent);
  process.stdout.write(
    `Bundled browser harness page (${(js.length / 1024).toFixed(1)} KiB)\n`,
  );
} catch (error) {
  process.stderr.write(
    `Failed to bundle browser harness page: ${
      error instanceof Error ? error.message : String(error)
    }\n`,
  );
  process.exit(1);
}
